const { spawn } = require('child_process');

async function resizeImage(inputFilename, outputFilename, dimensions, effects) {
  const imageMagickCommand = `convert ${inputFilename} -resize ${dimensions} ${effects.join(' ')} ${outputFilename}`;
  const graphicsMagickCommand = `gm convert ${inputFilename} -resize ${dimensions} ${effects.join(' ')} ${outputFilename}`;

  let command, result;
  try {
    command = await spawn(imageMagickCommand);
  } catch (e) {
    try {
      command = await spawn(graphicsMagickCommand);
    } catch (e) {
      throw new Error('Could not run ImageMagick or GraphicsMagick');
    }
  }

  result = await command.wait();

  return result;
}